document.addEventListener("DOMContentLoaded", () => {
  const ITEMS_PER_PAGE = 30;
  const items = Array.from(document.querySelectorAll(".client-item"));
  const loadMoreBtn = document.getElementById("load-more-btn");
  const loadMoreContainer = document.querySelector(".load-more-container");

  // New overlay filter elements
  const toggleBtn = document.getElementById("filter-toggle-btn");
  const dropdown = document.getElementById("filter-dropdown");
  const activeLabel = document.getElementById("filter-active-label");
  const filterOpts = document.querySelectorAll(".filter-opt");

  let currentCategory = "all";
  let visibleCount = ITEMS_PER_PAGE;

  /* ── Tooltip names from alt text ── */
  items.forEach(item => {
    const img = item.querySelector("img");
    if (img) {
      let name = img.getAttribute("alt") || "Partner";
      name = name.replace(/[-_]/g, " ").replace(/\.png|\.jpg|\.jpeg|\.svg|\.webp/gi, "");
      name = name.replace(/\b\w/g, l => l.toUpperCase());
      item.setAttribute("data-tooltip", name);
      item.setAttribute("aria-label", name);
      if (!item.hasAttribute("tabindex")) item.setAttribute("tabindex", "0");
      img.setAttribute("title", name);
    }
  });

  /* ── Render visible items ── */
  function renderItems() {
    let shown = 0;
    let hasMore = false;
    items.forEach(item => {
      const cat = item.getAttribute("data-category");
      const match = currentCategory === "all" || cat === currentCategory;
      if (match) {
        if (shown < visibleCount) {
          item.classList.remove("hidden");
          item.classList.add("visible");
          shown++;
        } else {
          item.classList.add("hidden");
          item.classList.remove("visible");
          hasMore = true;
        }
      } else {
        item.classList.add("hidden");
        item.classList.remove("visible");
      }
    });
    if (loadMoreContainer) {
      loadMoreContainer.style.display = hasMore ? "flex" : "none";
    }
  }

  /* ── Open / close dropdown ── */
  function openDropdown() {
    dropdown.classList.add("open");
    toggleBtn.setAttribute("aria-expanded", "true");
  }

  function closeDropdown() {
    dropdown.classList.remove("open");
    toggleBtn.setAttribute("aria-expanded", "false");
  }

  if (toggleBtn) {
    toggleBtn.addEventListener("click", e => {
      e.stopPropagation();
      dropdown.classList.contains("open") ? closeDropdown() : openDropdown();
    });

    // Close on outside click
    document.addEventListener("click", e => {
      if (dropdown && !dropdown.contains(e.target) && e.target !== toggleBtn) {
        closeDropdown();
      }
    });

    // Close on Escape
    document.addEventListener("keydown", e => {
      if (e.key === "Escape") closeDropdown();
    });
  }

  /* ── Filter option click ── */
  if (filterOpts) {
    filterOpts.forEach(opt => {
      opt.addEventListener("click", () => {
        filterOpts.forEach(o => {
          o.classList.remove("active");
          o.setAttribute("aria-selected", "false");
        });
        opt.classList.add("active");
        opt.setAttribute("aria-selected", "true");

        currentCategory = opt.getAttribute("data-filter");
        visibleCount = ITEMS_PER_PAGE;

        // Update button label
        const labelMap = {
          "all": "All",
          "industrial": "Manufacturing",
          "real-estate": "Real Estate",
          "tech": "Technology",
          "finance": "Finance",
          "hospitality": "Hospitality",
          "healthcare": "Healthcare"
        };
        activeLabel.textContent = labelMap[currentCategory] || "All";

        renderItems();
        closeDropdown();
      });
    });

    /* ── Load more ── */
    if (loadMoreBtn) {
      loadMoreBtn.addEventListener("click", () => {
        visibleCount = items.length;
        renderItems();
      });
    }

    renderItems();
  };

  /* ── Fade-in animation ── */
  const style = document.createElement("style");
  style.innerHTML = `
.client-item { transition: opacity 0.5s ease, transform 0.5s ease; opacity: 1; }
.client-item.hidden { display: none; opacity: 0; }
.visible { animation: fadeIn 0.5s forwards; }
@keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
`;
  document.head.appendChild(style);
})